public class XSSSecureCode {
    public static void main(String[] args) {
        // Simulating user input from a form field
        String userInput = "<script>alert('XSS Vulnerability!')</script>";

        // Sanitize user input to prevent XSS attacks
        String sanitizedInput = sanitizeUserInput(userInput);

        // Displaying the sanitized user input
        System.out.println("User input: " + sanitizedInput);
    }

    // Function to sanitize user input by escaping special characters
    private static String sanitizeUserInput(String input) {
        return input.replaceAll("<", "&lt;")
                    .replaceAll(">", "&gt;")
                    .replaceAll("\"", "&quot;")
                    .replaceAll("'", "&#39;")
                    .replaceAll("&", "&amp;");
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
